1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Customer {
27	  yearsWithMHPCO: number;
28	}
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	type QuoteResult = { premium: number };
36	type ClaimResult = { payout: number; remainingCap: number };
37	type StepResult = QuoteResult | ClaimResult;
38	
39	const BASE_PREMIUM: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	  moonstone: 25,
46	};
47	
48	const INSURANCE_VALUE: Record<string, number> = {
49	  sword: 1000,
50	  amulet: 600,
51	  staff: 800,
52	  potion: 400,
53	  rune: 250,
54	  moonstone: 250,
55	};
56	
57	const FIRST_INSURANCE_RATE = 0.1;
58	const PROCESSING_FEE = 5;
59	const LOYALTY_THRESHOLD_YEARS = 2;
60	const LOYALTY_DISCOUNT_RATE = 0.2;
61	const FOLLOWUP_DISCOUNT_RATE = 0.15;
62	const DEDUCTIBLE = 100;
63	const HIGH_DAMAGE_ENCHANTMENT_THRESHOLD = 8;
64	const HALF_REIMBURSEMENT_RATE = 0.5;
65	
66	const COMPONENT_TYPES = ["rune", "moonstone"];
67	const COMPONENT_BLOCK_SIZE = 3;
68	const COMPONENT_BLOCK_PREMIUM = 60;
69	
70	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
71	
72	const typeBasePremium = (type: string, count: number): number =>
73	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
74	    ? COMPONENT_BLOCK_PREMIUM
75	    : count * BASE_PREMIUM[type];
76	
77	const CURSE_RATE = 0.5;
78	const HIGH_ENCHANTMENT_THRESHOLD = 5;
79	const HIGH_ENCHANTMENT_RATE = 0.3;
80	
81	const surchargeForItem = (item: Item): number => {
82	  const base = BASE_PREMIUM[item.type];
83	  const curse = item.cursed ? CURSE_RATE * base : 0;
84	  const highEnchantment =
85	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
86	      ? HIGH_ENCHANTMENT_RATE * base
87	      : 0;
88	  return curse + highEnchantment;
89	};
90	
91	const itemSurcharges = (items: Item[]): number =>
92	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
93	
94	const countByType = (items: Item[]): Map<string, number> => {
95	  const counts = new Map<string, number>();
96	  for (const item of items) {
97	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
98	  }
99	  return counts;
100	};
101	
102	const policyBasePremium = (items: Item[]): number =>
103	  [...countByType(items)].reduce(
104	    (total, [type, count]) => total + typeBasePremium(type, count),
105	    0,
106	  );
107	
108	const isLoyal = (customer: Customer): boolean =>
109	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
110	
111	const policyModifierRate = (customer: Customer, isFollowup: boolean): number =>
112	  FIRST_INSURANCE_RATE -
113	  (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0) -
114	  (isFollowup ? FOLLOWUP_DISCOUNT_RATE : 0);
115	
116	const quotePremium = (
117	  step: QuoteStep,
118	  customer: Customer,
119	  isFollowup: boolean,
120	): number => {
121	  const policyBase = policyBasePremium(step.items);
122	  const policyModifierAmount =
123	    policyBase * policyModifierRate(customer, isFollowup);
124	  return Math.ceil(
125	    policyBase +
126	      itemSurcharges(step.items) +
127	      policyModifierAmount +
128	      PROCESSING_FEE,
129	  );
130	};
131	
132	const insuranceSum = (items: Item[]): number =>
133	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
134	
135	const isHighlyEnchanted = (item: Item | undefined): boolean =>
136	  (item?.enchantment ?? 0) >= HIGH_DAMAGE_ENCHANTMENT_THRESHOLD;
137	
138	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
139	  isHighlyEnchanted(item)
140	    ? HALF_REIMBURSEMENT_RATE * damage.amount
141	    : damage.amount;
142	
143	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
144	  const item = policyItems.find((it) => it.type === damage.itemType);
145	  return reimbursableAmount(damage, item) - DEDUCTIBLE;
146	};
147	
148	const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
149	  const cap = 2 * insuranceSum(policyItems);
150	  const payout = step.incident.damages.reduce(
151	    (sum, damage) => sum + damagePayout(damage, policyItems),
152	    0,
153	  );
154	  return { payout: Math.floor(payout), remainingCap: cap - payout };
155	};
156	
157	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
158	  const policyItemsByStep = new Map<number, Item[]>();
159	  let quoteCount = 0;
160	  const results: StepResult[] = [];
161	  scenario.steps.forEach((step, index) => {
162	    if (step.op === "quote") {
163	      const isFollowup = quoteCount > 0;
164	      results.push({ premium: quotePremium(step, scenario.customer, isFollowup) });
165	      policyItemsByStep.set(index, step.items);
166	      quoteCount += 1;
167	    } else {
168	      const policyItems = policyItemsByStep.get(step.policy) ?? [];
169	      results.push(claimResult(step, policyItems));
170	    }
171	  });
172	  return { results };
173	};
